mapper.select:
/** CmmtEventDao.selectList */ select , #{totalItems} + 1 - (row_number() over(order by created_dt desc)) as rn from cmmt_event where
order by created_dt desc
offset #{beginRowNum} - 1 limit #{itemsPerPage}

/** CmmtEventDao.select */
select

from cmmt_event
where
	event_id = #{eventId}

mapper.update:
/** CmmtEventDao.update */
update cmmt_event set
	 event_id				  = #{eventId}
	,event_nm                 = #{eventNm}
	,posting                  = #{posting}
	,begin_day                = #{beginDay}
	,end_day                  = #{endDay}
	,pc_thumbnail_file_id     = #{pcThumbnailFileId}
	,mobile_thumbnail_file_id = #{mobileThumbnailFileId}
	,thumbnail_alt_cn		  = #{thumbnailAltCn}
	,pc_image_file_id         = #{pcImageFileId}
	,mobile_image_file_id     = #{mobileImageFileId}
	,image_alt_cn			  = #{imageAltCn}
	,url                      = #{url}
	,new_window               = #{newWindow}
	,attachment_group_id      = #{attachmentGroupId}
	,read_cnt				  = #{readCnt}
	,creator_id               = #{creatorId}
	,created_dt               = #{createdDt}
	,updater_id               = #{updaterId}
	,updated_dt               = #{updatedDt}
where
	event_id = #{eventId}

mapper.insert:
/** CmmtEventDao.delete */
delete from
	cmmt_event
where
	event_id = #{eventId}

mapper.select:
/** CmmtEventDao.selectList_today */ select
from cmmt_event where posting = true and (
begin_day <= to_char(now(), 'yyyymmdd') and end_day >= to_char(now(), 'yyyymmdd')
)

/** CmmtEventDao.selectList_time */ select event_id ,event_nm ,begin_day ,end_day ,pc_thumbnail_file_id ,mobile_thumbnail_file_id ,thumbnail_alt_cn ,url ,new_window ,read_cnt ,creator_id ,created_dt ,updater_id ,updated_dt ,row_number() over(order by begin_day, created_dt) as rn from cmmt_event where posting = true
and begin_day <= to_char(now(), 'yyyymmdd') and end_day >= to_char(now(), 'yyyymmdd')
order by begin_day ,created_dt offset 0 limit #{searchCnt}
